-    const shas = files.map(f => f.sha);
-    const chunkMeta = this.engine.lookupChunkMeta(shas);
-    const metaBySha = new Map(chunkMeta.map(m => [m.sha, m]));
-
-    const grepEntries = files.map(f => {
-      const meta = metaBySha.get(f.sha);
