-      const head = this.engine.getHead();
-      if (!head) return null;
-      if (head.startsWith("ref: ")) {
-        const targetRef = head.slice(5).replace(/^refs\//, "");
-        return this.engine.getRef(targetRef);
-      }
-      return head; // detached HEAD (raw sha)
