-      `parent ${targetSha}`,
-      `author ${commitInfo.author} <${commitInfo.authorEmail}> ${commitInfo.authorTimestamp} +0000`,
-      `committer ${opts.author} <${opts.email}> ${ts} +0000`,
-      "",
-      commitInfo.message,
