-    if (commitInfo.parents.length === 0) throw new Error("Cannot revert initial commit");
-
-    const targetObj = objs.get(targetSha);
-    if (!targetObj || targetObj.type !== OBJ_COMMIT) throw new Error("Target is not a commit");
