-  for (const p of byChunks.delimitedPrefixes) {
-    const repoPath = p.replace(/\/chunks\/$/, "");
-    if (seen.has(repoPath)) continue;
-    seen.add(repoPath);
-    const [owner, name] = repoPath.split("/");
-    if (owner && name) repos.push({ owner, name });
-  }
